#include <bits/stdc++.h>
using namespace std;
bool a(long long x,long long y){
    return x*x*x<=y;
}
int main(){
    long long n;
    cin>>n;
    long long l=1,r=1000000,m,ans=0;
    while(l<=r){
        m=(l+r)/2;
        if (a(m,n)==1){
            ans=max(ans,m);
            l=m+1;
        }
        else{
            r=m-1;
        }
    }
    cout<<ans;
    return 0;
}
